#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

const GENERATED_NOTICE = [
	'<!--',
	'This file is auto-generated by scripts/hooks/generate-hook-docs.js.',
	'Do not edit manually.',
	'-->',
	'',
].join('\n');

function parseArgs() {
	const args = {};

	process.argv.slice(2).forEach((arg) => {
		const [rawKey, ...valueParts] = arg.replace(/^--/, '').split('=');
		const value = valueParts.join('=');
		args[rawKey] = value === '' ? true : value;
	});

	return args;
}

function readJson(filePath) {
	if (!fs.existsSync(filePath)) {
		throw new Error(`File not found: ${filePath}`);
	}

	return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

function ensureDir(dirPath) {
	if (!fs.existsSync(dirPath)) {
		fs.mkdirSync(dirPath, { recursive: true });
	}
}

function walkPhpFiles(entryPath, acc = []) {
	if (!fs.existsSync(entryPath)) {
		return acc;
	}

	const stat = fs.statSync(entryPath);
	if (stat.isFile() && entryPath.endsWith('.php')) {
		acc.push(entryPath);
		return acc;
	}

	if (stat.isDirectory()) {
		const children = fs.readdirSync(entryPath);
		children.forEach((child) => {
			walkPhpFiles(path.join(entryPath, child), acc);
		});
	}

	return acc;
}

function parseDocblock(rawDocblock) {
	if (!rawDocblock) {
		return {
			description: '',
			since: null,
			hookGroup: null,
			params: [],
		};
	}

	const lines = rawDocblock
		.replace(/^\/\*\*/, '')
		.replace(/\*\/$/, '')
		.split('\n')
		.map((line) => line.replace(/^\s*\*\s?/, '').trimEnd());

	const descriptionLines = [];
	const params = [];
	let since = null;
	let hookGroup = null;
	let inTags = false;

	lines.forEach((line) => {
		const trimmed = line.trim();
		if (trimmed.startsWith('@')) {
			inTags = true;
		}

		if (!inTags && trimmed !== '') {
			descriptionLines.push(trimmed);
		}

		const paramMatch = trimmed.match(/^@param\s+(\S+)\s+(\$\S+)\s*(.*)$/);
		if (paramMatch) {
			params.push({
				type: paramMatch[1],
				name: paramMatch[2],
				description: paramMatch[3] || '',
			});
		}

		const sinceMatch = trimmed.match(/^@since\s+(.+)$/);
		if (sinceMatch) {
			since = sinceMatch[1].trim();
		}

		const hookGroupMatch = trimmed.match(/^@hookGroup\s+([a-z0-9_-]+)$/i);
		if (hookGroupMatch) {
			hookGroup = hookGroupMatch[1].toLowerCase();
		}
	});

	return {
		description: descriptionLines.join(' ').trim(),
		since,
		hookGroup,
		params,
	};
}

function getLineNumber(content, index) {
	return content.slice(0, index).split('\n').length;
}

function extractCallAt(content, functionName, startIndex) {
	const functionIndex = content.indexOf(functionName, startIndex);
	if (functionIndex === -1) {
		return null;
	}

	let i = functionIndex + functionName.length;
	while (i < content.length && /\s/.test(content[i])) {
		i++;
	}

	if (content[i] !== '(') {
		return null;
	}

	const openParenIndex = i;
	let depth = 0;
	let inString = null;
	let isEscaped = false;

	for (let cursor = openParenIndex; cursor < content.length; cursor++) {
		const char = content[cursor];

		if (inString) {
			if (!isEscaped && char === inString) {
				inString = null;
			}
			isEscaped = !isEscaped && char === '\\';
			continue;
		}

		if (char === '"' || char === '\'') {
			inString = char;
			isEscaped = false;
			continue;
		}

		if (char === '(') {
			depth++;
		} else if (char === ')') {
			depth--;
			if (depth === 0) {
				const argsSource = content.slice(openParenIndex + 1, cursor);

				let semicolonIndex = cursor + 1;
				while (semicolonIndex < content.length && /\s/.test(content[semicolonIndex])) {
					semicolonIndex++;
				}

				if (content[semicolonIndex] !== ';') {
					return null;
				}

				return {
					functionName,
					functionIndex,
					argsSource,
					endIndex: semicolonIndex,
					line: getLineNumber(content, functionIndex),
				};
			}
		}
	}

	return null;
}

function splitTopLevelArgs(argsSource) {
	const args = [];
	let current = '';
	let depthParen = 0;
	let depthBracket = 0;
	let depthBrace = 0;
	let inString = null;
	let isEscaped = false;

	for (let i = 0; i < argsSource.length; i++) {
		const char = argsSource[i];

		if (inString) {
			current += char;
			if (!isEscaped && char === inString) {
				inString = null;
			}
			isEscaped = !isEscaped && char === '\\';
			continue;
		}

		if (char === '"' || char === '\'') {
			inString = char;
			isEscaped = false;
			current += char;
			continue;
		}

		if (char === '(') {
			depthParen++;
			current += char;
			continue;
		}
		if (char === ')') {
			depthParen--;
			current += char;
			continue;
		}
		if (char === '[') {
			depthBracket++;
			current += char;
			continue;
		}
		if (char === ']') {
			depthBracket--;
			current += char;
			continue;
		}
		if (char === '{') {
			depthBrace++;
			current += char;
			continue;
		}
		if (char === '}') {
			depthBrace--;
			current += char;
			continue;
		}

		if (char === ',' && depthParen === 0 && depthBracket === 0 && depthBrace === 0) {
			args.push(current.trim());
			current = '';
			continue;
		}

		current += char;
	}

	if (current.trim()) {
		args.push(current.trim());
	}

	return args;
}

function parseHookNameExpression(firstArg) {
	if (!firstArg) {
		return {
			name: null,
			isDynamic: true,
			rawExpression: '',
		};
	}

	const singleQuoted = firstArg.match(/^'([^']+)'$/);
	if (singleQuoted) {
		return {
			name: singleQuoted[1],
			isDynamic: false,
			rawExpression: firstArg,
		};
	}

	const doubleQuoted = firstArg.match(/^"([^"]+)"$/);
	if (doubleQuoted) {
		const value = doubleQuoted[1];
		const hasInterpolation = /\$|\{/.test(value);
		return {
			name: hasInterpolation ? value : value,
			isDynamic: hasInterpolation,
			rawExpression: firstArg,
		};
	}

	return {
		name: firstArg,
		isDynamic: true,
		rawExpression: firstArg,
	};
}

function getNearestDocblock(content, functionIndex) {
	let searchFrom = functionIndex;

	while (searchFrom > 0) {
		const docblockStart = content.lastIndexOf('/**', searchFrom);
		if (docblockStart === -1) {
			return null;
		}

		const docblockEnd = content.indexOf('*/', docblockStart);
		if (docblockEnd === -1 || docblockEnd > functionIndex) {
			searchFrom = docblockStart - 1;
			continue;
		}

		const between = content.slice(docblockEnd + 2, functionIndex);
		if (!/^\s*$/.test(between)) {
			return null;
		}

		return content.slice(docblockStart, docblockEnd + 2).trim();
	}

	return null;
}

function loadSnippets(snippetsDir) {
	if (!fs.existsSync(snippetsDir)) {
		return {
			byHookName: {},
			total: 0,
		};
	}

	const files = fs
		.readdirSync(snippetsDir)
		.filter((file) => file.endsWith('.md') || file.endsWith('.mdx'));

	const byHookName = {};

	files.forEach((fileName) => {
		const fullPath = path.join(snippetsDir, fileName);
		const content = fs.readFileSync(fullPath, 'utf8');
		const frontmatterMatch = content.match(/^---\n([\s\S]*?)\n---\n?/);

		if (!frontmatterMatch) {
			return;
		}

		const frontmatter = parseFrontmatter(frontmatterMatch[1]);
		const hookNames = Array.isArray(frontmatter.hookNames) ? frontmatter.hookNames : [];
		const title = typeof frontmatter.title === 'string' ? frontmatter.title : fileName;
		const relativePath = path.relative(process.cwd(), fullPath);

		hookNames.forEach((hookName) => {
			if (!byHookName[hookName]) {
				byHookName[hookName] = [];
			}

			byHookName[hookName].push({
				title,
				path: relativePath,
			});
		});
	});

	return {
		byHookName,
		total: files.length,
	};
}

function parseFrontmatter(source) {
	const result = {};
	const lines = source.split('\n');
	let currentArrayKey = null;

	lines.forEach((line) => {
		const trimmed = line.trim();
		if (!trimmed || trimmed.startsWith('#')) {
			return;
		}

		if (trimmed.startsWith('- ') && currentArrayKey) {
			result[currentArrayKey].push(trimmed.replace(/^- /, '').trim());
			return;
		}

		const keyValueMatch = trimmed.match(/^([A-Za-z0-9_]+):\s*(.*)$/);
		if (!keyValueMatch) {
			currentArrayKey = null;
			return;
		}

		const key = keyValueMatch[1];
		const rawValue = keyValueMatch[2].trim();

		if (rawValue === '') {
			result[key] = [];
			currentArrayKey = key;
			return;
		}

		currentArrayKey = null;
		if (rawValue.startsWith('[') && rawValue.endsWith(']')) {
			result[key] = rawValue
				.slice(1, -1)
				.split(',')
				.map((item) => item.trim().replace(/^['"]|['"]$/g, ''))
				.filter(Boolean);
			return;
		}

		result[key] = rawValue.replace(/^['"]|['"]$/g, '');
	});

	return result;
}

function getDefaultGroup(groups) {
	return groups.find((group) => group.id === 'uncategorized') || groups[0];
}

function assignGroup(hook, groups) {
	if (hook.docblock.hookGroup) {
		const explicitGroup = groups.find((group) => group.id === hook.docblock.hookGroup);
		if (explicitGroup) {
			return {
				group: explicitGroup,
				source: 'explicit',
			};
		}

		return {
			group: getDefaultGroup(groups),
			source: 'invalid',
		};
	}

	if (typeof hook.name !== 'string' || hook.isDynamic) {
		return {
			group: getDefaultGroup(groups),
			source: 'fallback',
		};
	}

	for (const group of groups) {
		const patterns = Array.isArray(group.match) ? group.match : [];
		for (const pattern of patterns) {
			const regex = new RegExp(pattern);
			if (regex.test(hook.name)) {
				return {
					group,
					source: 'fallback',
				};
			}
		}
	}

	return {
		group: getDefaultGroup(groups),
		source: 'fallback',
	};
}

function buildHookRecord({
	pluginSlug,
	hook,
	groupAssignment,
	relativeFilePath,
	snippetMap,
}) {
	const relatedSnippets = snippetMap[hook.name] || [];

	return {
		pluginSlug,
		name: hook.name,
		kind: hook.kind,
		group: groupAssignment.group.id,
		groupLabel: groupAssignment.group.label,
		groupSource: groupAssignment.source,
		file: relativeFilePath,
		line: hook.line,
		description: hook.docblock.description,
		params: hook.docblock.params,
		since: hook.docblock.since,
		hookGroup: hook.docblock.hookGroup,
		isDynamic: hook.isDynamic,
		rawExpression: hook.rawExpression,
		relatedSnippets,
	};
}

function slugFromHookName(hookName) {
	return hookName.toLowerCase().replace(/[^a-z0-9_-]+/g, '-');
}

function renderHookDoc(hook) {
	const title = hook.name || hook.rawExpression || 'unknown_hook';
	const params = hook.params || [];
	const snippets = hook.relatedSnippets || [];
	const description = hook.description || 'No description available.';

	const lines = [];
	lines.push(GENERATED_NOTICE.trimEnd());
	lines.push('---');
	lines.push(`title: ${title}`);
	lines.push(`hookType: ${hook.kind}`);
	lines.push(`hookGroup: ${hook.group}`);
	lines.push(`plugin: ${hook.pluginSlug}`);
	lines.push('---');
	lines.push('');
	lines.push(`# \`${title}\``);
	lines.push('');
	lines.push(description);
	lines.push('');
	lines.push(`- **Type:** ${hook.kind}`);
	lines.push(`- **Group:** ${hook.groupLabel}`);
	lines.push(`- **Since:** ${hook.since || 'Unknown'}`);
	lines.push(`- **Source:** \`${hook.file}\``);
	lines.push('');

	if (params.length > 0) {
		lines.push('## Parameters');
		lines.push('');
		params.forEach((param) => {
			lines.push(`- \`${param.name}\` (\`${param.type}\`): ${param.description || 'No description.'}`);
		});
		lines.push('');
	}

	if (snippets.length > 0) {
		lines.push('## Related Snippets');
		lines.push('');
		snippets.forEach((snippet) => {
			lines.push(`- [${snippet.title}](/${snippet.path})`);
		});
		lines.push('');
	}

	return lines.join('\n');
}

function groupHooks(hooks) {
	return hooks.reduce((acc, hook) => {
		if (!acc[hook.group]) {
			acc[hook.group] = [];
		}
		acc[hook.group].push(hook);
		return acc;
	}, {});
}

function renderIndexPage({ title, kind, hooks }) {
	const grouped = groupHooks(hooks);
	const orderedGroups = Object.keys(grouped).sort((a, b) => a.localeCompare(b));

	const lines = [];
	lines.push(GENERATED_NOTICE.trimEnd());
	lines.push('---');
	lines.push(`title: ${title}`);
	lines.push('---');
	lines.push('');
	lines.push(`# ${title}`);
	lines.push('');

	if (hooks.length === 0) {
		lines.push('No hooks found.');
		lines.push('');
		return lines.join('\n');
	}

	orderedGroups.forEach((groupId) => {
		const groupHooksList = grouped[groupId];
		const label = groupHooksList[0]?.groupLabel || groupId;

		lines.push(`## ${label}`);
		lines.push('');
		groupHooksList
			.sort((a, b) => (a.name || '').localeCompare(b.name || ''))
			.forEach((hook) => {
				const slug = slugFromHookName(hook.name);
				lines.push(`- [\`${hook.name}\`](/docs/${kind}/${slug})`);
			});
		lines.push('');
	});

	return lines.join('\n');
}

function writeGeneratedOutputs({
	docsDir,
	actions,
	filters,
	indexPayload,
	validateOnly,
}) {
	const generatedDir = path.join(docsDir, 'generated');
	const actionsDir = path.join(docsDir, 'actions');
	const filtersDir = path.join(docsDir, 'filters');

	const filesToWrite = [];
	filesToWrite.push({
		path: path.join(generatedDir, 'hooks-index.json'),
		content: `${JSON.stringify(indexPayload, null, 2)}\n`,
	});
	filesToWrite.push({
		path: path.join(generatedDir, 'hooks-lint.json'),
		content: `${JSON.stringify(indexPayload.lint, null, 2)}\n`,
	});
	filesToWrite.push({
		path: path.join(actionsDir, 'index.md'),
		content: renderIndexPage({
			title: 'Actions',
			kind: 'actions',
			hooks: actions.filter((hook) => !hook.isDynamic && hook.name),
		}),
	});
	filesToWrite.push({
		path: path.join(filtersDir, 'index.md'),
		content: renderIndexPage({
			title: 'Filters',
			kind: 'filters',
			hooks: filters.filter((hook) => !hook.isDynamic && hook.name),
		}),
	});

	actions
		.filter((hook) => !hook.isDynamic && hook.name)
		.forEach((hook) => {
			filesToWrite.push({
				path: path.join(actionsDir, `${slugFromHookName(hook.name)}.md`),
				content: renderHookDoc(hook),
			});
		});

	filters
		.filter((hook) => !hook.isDynamic && hook.name)
		.forEach((hook) => {
			filesToWrite.push({
				path: path.join(filtersDir, `${slugFromHookName(hook.name)}.md`),
				content: renderHookDoc(hook),
			});
		});

	if (validateOnly) {
		const changedFiles = filesToWrite
			.filter((file) => fs.existsSync(file.path))
			.filter((file) => fs.readFileSync(file.path, 'utf8') !== file.content)
			.map((file) => path.relative(process.cwd(), file.path));

		if (changedFiles.length > 0) {
			throw new Error(
				`Generated files are stale. Re-run hooks generator. Changed files:\n${changedFiles
					.map((item) => `- ${item}`)
					.join('\n')}`
			);
		}

		return;
	}

	ensureDir(generatedDir);
	ensureDir(actionsDir);
	ensureDir(filtersDir);

	filesToWrite.forEach((file) => {
		fs.writeFileSync(file.path, file.content, 'utf8');
	});
}

function extractHooksFromFile(filePath, repoRoot) {
	const content = fs.readFileSync(filePath, 'utf8');
	const hooks = [];

	let cursor = 0;
	while (cursor < content.length) {
		const doActionIndex = content.indexOf('do_action', cursor);
		const applyFiltersIndex = content.indexOf('apply_filters', cursor);

		const candidates = [doActionIndex, applyFiltersIndex].filter((index) => index >= 0);
		if (candidates.length === 0) {
			break;
		}

		const nextIndex = Math.min(...candidates);
		const fnName = nextIndex === doActionIndex ? 'do_action' : 'apply_filters';
		const extracted = extractCallAt(content, fnName, nextIndex);

		if (!extracted) {
			cursor = nextIndex + fnName.length;
			continue;
		}

		const args = splitTopLevelArgs(extracted.argsSource);
		const firstArg = args[0] || '';
		const parsedName = parseHookNameExpression(firstArg);
		const docblock = parseDocblock(getNearestDocblock(content, extracted.functionIndex));

		hooks.push({
			name: parsedName.name,
			rawExpression: parsedName.rawExpression,
			isDynamic: parsedName.isDynamic,
			kind: fnName === 'do_action' ? 'action' : 'filter',
			file: path.relative(repoRoot, filePath),
			line: extracted.line,
			docblock,
		});

		cursor = extracted.endIndex + 1;
	}

	return hooks;
}

function main() {
	const args = parseArgs();
	const repoRoot = process.cwd();
	const pluginSlug = args.plugin;

	if (!pluginSlug) {
		console.error('Error: --plugin is required');
		console.error('Usage: node scripts/hooks/generate-hook-docs.js --plugin=wp-graphql');
		process.exit(1);
	}

	const configPath = args.config
		? path.resolve(repoRoot, args.config)
		: path.resolve(repoRoot, 'scripts/hooks/plugin-config.json');
	const groupsPath = args.groups
		? path.resolve(repoRoot, args.groups)
		: path.resolve(repoRoot, 'scripts/hooks/groups.json');

	const pluginConfigMap = readJson(configPath);
	const groups = readJson(groupsPath);
	const pluginConfig = pluginConfigMap[pluginSlug];
	const validateOnly = args['validate-only'] === 'true' || args['validate-only'] === true;
	const requireExplicitGroup =
		args['require-explicit-group'] === 'true' || args['require-explicit-group'] === true;

	if (!pluginConfig) {
		console.error(`Error: Plugin "${pluginSlug}" not found in ${configPath}`);
		process.exit(1);
	}

	const pluginDir = path.resolve(repoRoot, pluginConfig.pluginDir);
	const docsDir = path.resolve(repoRoot, pluginConfig.docsDir);
	const snippetsDir = path.resolve(repoRoot, pluginConfig.snippetsDir || '');

	const sourcePaths = Array.isArray(pluginConfig.sourcePaths) ? pluginConfig.sourcePaths : ['src'];
	const phpFiles = [];
	sourcePaths.forEach((sourcePath) => {
		const fullPath = path.resolve(pluginDir, sourcePath);
		walkPhpFiles(fullPath, phpFiles);
	});

	const snippets = loadSnippets(snippetsDir);
	const hookRecords = [];
	const lint = {
		errors: [],
		warnings: [],
	};

	phpFiles.forEach((phpFile) => {
		const extractedHooks = extractHooksFromFile(phpFile, repoRoot);
		extractedHooks.forEach((hook) => {
			const groupAssignment = assignGroup(hook, groups);
			const record = buildHookRecord({
				pluginSlug,
				hook,
				groupAssignment,
				relativeFilePath: hook.file,
				snippetMap: snippets.byHookName,
			});

			if (hook.docblock.hookGroup && groupAssignment.source === 'invalid') {
				lint.errors.push({
					type: 'invalid_hook_group',
					hook: hook.name,
					file: hook.file,
					line: hook.line,
					message: `Invalid @hookGroup "${hook.docblock.hookGroup}"`,
				});
			}

			if (!hook.docblock.hookGroup) {
				const warning = {
					type: 'missing_hook_group',
					hook: hook.name,
					file: hook.file,
					line: hook.line,
					message: 'Missing @hookGroup tag',
				};
				if (requireExplicitGroup) {
					lint.errors.push(warning);
				} else {
					lint.warnings.push(warning);
				}
			}

			hookRecords.push(record);
		});
	});

	const actions = hookRecords.filter((hook) => hook.kind === 'action');
	const filters = hookRecords.filter((hook) => hook.kind === 'filter');

	const payload = {
		plugin: pluginSlug,
		generatedAt: new Date().toISOString(),
		stats: {
			totalHooks: hookRecords.length,
			actions: actions.length,
			filters: filters.length,
			dynamic: hookRecords.filter((hook) => hook.isDynamic).length,
			snippets: snippets.total,
		},
		groups,
		lint,
		hooks: hookRecords.sort((a, b) => {
			const nameCompare = (a.name || '').localeCompare(b.name || '');
			if (nameCompare !== 0) {
				return nameCompare;
			}
			return a.file.localeCompare(b.file);
		}),
	};

	writeGeneratedOutputs({
		docsDir,
		actions,
		filters,
		indexPayload: payload,
		validateOnly,
	});

	if (lint.warnings.length > 0) {
		console.warn(`Warnings: ${lint.warnings.length}`);
	}

	if (lint.errors.length > 0) {
		console.error(`Errors: ${lint.errors.length}`);
		process.exit(1);
	}

	console.log(
		`Generated hook docs for ${pluginSlug}: ${actions.length} actions, ${filters.length} filters`
	);
}

if (require.main === module) {
	main();
}

module.exports = {
	assignGroup,
	extractHooksFromFile,
	parseDocblock,
	parseFrontmatter,
	parseHookNameExpression,
	splitTopLevelArgs,
};
